//
import { roundedRect } from '../../../utils/zcsvgutils';
import { getBorderRadius, defined } from '../../../utils/zcutils';
import { getMarkValue } from '../../parser/parser-helpers';

function rectMark(config, cache) {
    return {
        config: {
            d: function (d, i) {
                let node = this,
                    args = [d, i],
                    newConfig = config.d ? getMarkValue(node, args, config, 'd', cache) : config,
                    isRange = ['x1', 'y1', 'x2', 'y2'].some((_) => defined(newConfig[_])),
                    _x,
                    _y,
                    _width,
                    _height,
                    _radius;

                let propMap = getPropMap(isRange);
                _x = getMarkValue(node, args, newConfig, propMap.x, cache);
                _y = getMarkValue(node, args, newConfig, propMap.y, cache);
                _width = getMarkValue(node, args, newConfig, propMap.width, cache);
                _height = getMarkValue(node, args, newConfig, propMap.height, cache);
                _radius = getMarkValue(node, args, newConfig, ['radius', 'borderRadius'], cache);

                return roundedRect(_x, _y, _width, _height, getBorderRadius(_radius), null, null, isRange);
            }
        },
        depends: {
            d: ['x', 'y', 'width', 'height', 'radius', 'borderRadius', 'x1', 'y1', 'x2', 'y2']
        }
    };
}

function getPropMap(isRange) {
    return isRange ? { x: 'x1', y: 'y1', width: 'x2', height: 'y2' } : { x: 'x', y: 'y', width: 'width', height: 'height' };
}

export { rectMark };
